{"plugin": "contractAudit", "action": "audit", "code": "pragma solidity ^0.8.0;
contract Test {
  function withdraw() public {
    (bool ok,) = msg.sender.call{value: address(this).balance}("");
    require(ok);
  }
}"}

{"plugin": "contractAudit", "action": "quickCheck", "code": "pragma solidity ^0.8.0;
contract Test {
  function destroy() public { selfdestruct(payable(msg.sender)); }
}"}

{"plugin": "contractAudit", "action": "explain", "code": "pragma solidity ^0.8.0;
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
contract MyToken is ERC20 {
  constructor() ERC20("MyToken", "MTK") {
    _mint(msg.sender, 1000000 * 10**18);
  }
}"}
